 1→export function jsonResponse(data: unknown, status: number = 200): Response {
 2→	return new Response(JSON.stringify(data), {
 3→		status,
 4→		headers: { 'content-type': 'application/json' }
 5→	});
 6→}
 7→
 8→export function errorResponse(message: string, status: number): Response {
 9→	return new Response(JSON.stringify({ error: message }), {
10→		status,
11→		headers: { 'content-type': 'application/json' }
12→	});
13→}
14→
15→export async function parseRequestBody<T>(request: Request): Promise<T> {
16→	const text = await request.text();
17→	if (!text) {
18→		throw new Error('Request body is empty');
19→	}
20→	return JSON.parse(text) as T;
21→}
