11→}
12→
13→export interface DockerContainerInfo {
14→	id: string;
15→	name: string;
16→	image: string;
17→	status: 'running' | 'stopped';
18→	network: string;
19→	/** Ports published to the host. HALO containers never publish ports — always empty. */
20→	publishedPorts: Record<string, unknown>;
