 1→import { randomUUID } from 'crypto';
 2→import type {
 3→	DockerService,
 4→	DockerContainerInfo,
 5→	CreateContainerOptions,
 6→	RemoveContainerOptions
 7→} from './docker-service.js';
 8→
 9→/**
10→ * In-memory fake implementation of DockerService for use in tests.
11→ * Does not require a real Docker daemon.
12→ */
13→export class FakeDockerService implements DockerService {
14→	private containers: Map<string, DockerContainerInfo> = new Map();
15→
16→	async create(options: CreateContainerOptions): Promise<DockerContainerInfo> {
17→		const existing = Array.from(this.containers.values()).find((c) => c.name === options.name);
18→		if (existing) {
19→			throw new Error(`Container '${options.name}' already exists`);
20→		}
21→
22→		const info: DockerContainerInfo = {
23→			id: randomUUID(),
24→			name: options.name,
25→			image: options.image,
26→			status: 'stopped',
27→			network: 'halo-net',
28→			publishedPorts: {}
29→		};
30→
31→		this.containers.set(info.id, info);
32→		return { ...info };
33→	}
34→
35→	async start(id: string): Promise<void> {
36→		const container = this.containers.get(id);
37→		if (!container) {
38→			throw new Error(`Container '${id}' not found`);
39→		}
40→		container.status = 'running';
41→	}
42→
43→	async stop(id: string): Promise<void> {
44→		const container = this.containers.get(id);
45→		if (!container) {
46→			throw new Error(`Container '${id}' not found`);
47→		}
48→		container.status = 'stopped';
49→	}
50→
51→	async remove(id: string, options: RemoveContainerOptions = {}): Promise<void> {
52→		const container = this.containers.get(id);
53→		if (!container) {
54→			throw new Error(`Container '${id}' not found`);
55→		}
56→		if (container.status === 'running' && !options.force) {
57→			throw new Error(`Container '${id}' is running — stop it first or use force`);
58→		}
59→		this.containers.delete(id);
60→	}
61→
62→	async list(): Promise<DockerContainerInfo[]> {
63→		return Array.from(this.containers.values()).map((c) => ({ ...c }));
64→	}
65→
66→	async inspect(id: string): Promise<DockerContainerInfo> {
67→		const container = this.containers.get(id);
68→		if (!container) {
69→			throw new Error(`Container '${id}' not found`);
70→		}
71→		return { ...container };
72→	}
73→}
