  1→import Database from 'better-sqlite3';
  2→
  3→export interface ContainerRow {
  4→	id: string;
  5→	name: string;
  6→	template_id: string;
  7→	status: string;
  8→	config: Record<string, unknown>;
  9→	created_at: string;
 10→	updated_at: string;
 11→}
 12→
 13→interface ContainerRaw {
 14→	id: string;
 15→	name: string;
 16→	template_id: string;
 17→	status: string;
 18→	config: string;
 19→	created_at: string;
 20→	updated_at: string;
 21→}
 22→
 23→interface CreateContainerInput {
 24→	id: string;
 25→	name: string;
 26→	template_id: string;
 27→	config: Record<string, unknown>;
 28→	status?: string;
 29→}
 30→
 31→interface UpdateContainerInput {
 32→	name?: string;
 33→	status?: string;
 34→	config?: Record<string, unknown>;
 35→}
 36→
 37→function deserialize(raw: ContainerRaw): ContainerRow {
 38→	return { ...raw, config: JSON.parse(raw.config) as Record<string, unknown> };
 39→}
 40→
 41→export function createContainer(db: Database.Database, input: CreateContainerInput): ContainerRow {
 42→	db.prepare(
 43→		`INSERT INTO containers (id, name, template_id, status, config)
 44→		 VALUES (?, ?, ?, ?, ?)`
 45→	).run(
 46→		input.id,
 47→		input.name,
 48→		input.template_id,
 49→		input.status ?? 'stopped',
 50→		JSON.stringify(input.config)
 51→	);
 52→	return getContainerById(db, input.id) as ContainerRow;
 53→}
 54→
 55→export function getContainerById(db: Database.Database, id: string): ContainerRow | null {
 56→	const raw = db.prepare('SELECT * FROM containers WHERE id = ?').get(id) as
 57→		| ContainerRaw
 58→		| undefined;
 59→	return raw ? deserialize(raw) : null;
 60→}
 61→
 62→export function getAllContainers(db: Database.Database): ContainerRow[] {
 63→	const rows = db.prepare('SELECT * FROM containers ORDER BY created_at').all() as ContainerRaw[];
 64→	return rows.map(deserialize);
 65→}
 66→
 67→export function updateContainer(
 68→	db: Database.Database,
 69→	id: string,
 70→	input: UpdateContainerInput
 71→): ContainerRow | null {
 72→	const fields: string[] = [];
 73→	const values: unknown[] = [];
 74→
 75→	if (input.name !== undefined) {
 76→		fields.push('name = ?');
 77→		values.push(input.name);
 78→	}
 79→	if (input.status !== undefined) {
 80→		fields.push('status = ?');
 81→		values.push(input.status);
 82→	}
 83→	if (input.config !== undefined) {
 84→		fields.push('config = ?');
 85→		values.push(JSON.stringify(input.config));
 86→	}
 87→
 88→	if (fields.length === 0) return getContainerById(db, id);
 89→
 90→	fields.push("updated_at = datetime('now')");
 91→	values.push(id);
 92→
 93→	db.prepare(`UPDATE containers SET ${fields.join(', ')} WHERE id = ?`).run(...values);
 94→	return getContainerById(db, id);
 95→}
 96→
 97→export function deleteContainer(db: Database.Database, id: string): void {
 98→	db.prepare('DELETE FROM containers WHERE id = ?').run(id);
 99→}
