 38→export class ContainerService {
 39→	constructor(
 40→		private db: Database.Database,
 41→		private docker: DockerService
 42→	) {}
 43→
 44→	async create(input: CreateContainerInput): Promise<Container> {
 45→		// Create Docker container first — Docker assigns the canonical ID
 46→		const dockerInfo = await this.docker.create({
 47→			name: input.name,
 48→			image: input.config.image ?? 'ubuntu:22.04',
 49→			env: input.config.env,
 50→			mounts: input.config.mounts,
 51→			ports: input.config.ports
 52→		});
 53→
 54→		// Persist to DB using Docker-assigned ID
 55→		const row = dbCreate(this.db, {
 56→			id: dockerInfo.id,
 57→			name: input.name,
 58→			template_id: input.templateId,
 59→			config: input.config as Record<string, unknown>,
 60→			status: 'stopped'
 61→		});
 62→		return toContainer(row);
 63→	}
 64→
 65→	async list(): Promise<Container[]> {
 66→		return getAllContainers(this.db).map(toContainer);
 67→	}
 68→
 69→	async get(id: string): Promise<Container | null> {
 70→		const row = getContainerById(this.db, id);
 71→		return row ? toContainer(row) : null;
 72→	}
 73→
 74→	async updateConfig(id: string, config: Partial<ContainerConfig>): Promise<Container | null> {
 75→		const existing = getContainerById(this.db, id);
 76→		if (!existing) return null;
 77→
 78→		const merged = { ...(existing.config as ContainerConfig), ...config };
 79→		const row = dbUpdate(this.db, id, { config: merged as Record<string, unknown> });
 80→		return row ? toContainer(row) : null;
 81→	}
 82→
 83→	async start(id: string): Promise<Container> {
 84→		const existing = getContainerById(this.db, id);
 85→		if (!existing) {
 86→			throw new Error(`Container '${id}' not found`);
 87→		}
 88→
 89→		await this.docker.start(id);
 90→		const row = dbUpdate(this.db, id, { status: 'running' })!;
 91→		return toContainer(row);
 92→	}
 93→
 94→	async stop(id: string): Promise<Container> {
 95→		const existing = getContainerById(this.db, id);
 96→		if (!existing) {
 97→			throw new Error(`Container '${id}' not found`);
 98→		}
 99→
100→		await this.docker.stop(id);
101→		const row = dbUpdate(this.db, id, { status: 'stopped' })!;
102→		return toContainer(row);
103→	}
104→
105→	async destroy(id: string): Promise<void> {
106→		const existing = getContainerById(this.db, id);
107→		if (!existing) {
108→			throw new Error(`Container '${id}' not found`);
109→		}
110→
111→		await this.docker.remove(id, { force: true });
112→		dbDelete(this.db, id);
113→	}
114→}
