 3→type ValidationSuccess<T> = { success: true; value: T };
 4→type ValidationFailure = { success: false; error: string };
 5→type ValidationResult<T> = ValidationSuccess<T> | ValidationFailure;
 6→
 7→export function validateContainerName(name: string): ValidationResult<string> {
 8→	if (name.length < 3) {
 9→		return { success: false, error: 'Container name must be at least 3 characters' };
10→	}
11→	if (name.length > 63) {
12→		return { success: false, error: 'Container name must be at most 63 characters' };
13→	}
14→	if (!/^[a-zA-Z0-9-]+$/.test(name)) {
15→		return {
16→			success: false,
17→			error: 'Container name may only contain alphanumeric characters and hyphens'
18→		};
19→	}
20→	return { success: true, value: name };
21→}
