23→const VALID_SESSION_TYPES: SessionType[] = ['claude', 'terminal', 'shell'];
24→
25→export function validateSessionType(type: string): ValidationResult<SessionType> {
26→	if ((VALID_SESSION_TYPES as string[]).includes(type)) {
27→		return { success: true, value: type as SessionType };
28→	}
29→	return {
30→		success: false,
31→		error: `Session type must be one of: ${VALID_SESSION_TYPES.join(', ')}`
32→	};
33→}
